                        "schema:identifier": "ds-rainprob-maharashtra-march-2025",
                        "schema:name": "Rainwater Probability Maharashtra March 2025",
                        "schema:description": "Historical and forecasted rainwater probability data",
                        "schema:temporalCoverage": "2025-03-01/2025-03-31",
                        "schema:spatialCoverage": {
                            "@type": "schema:Place",
                            "schema:name": "Amravati, Maharashtra (user GPS)",
