                                "@type": "schema:GeoCoordinates",
                                "schema:latitude": 20.9374,
                                "schema:longitude": 77.7796
                            }
                        },
                        "dataset:locationOfInterestType": "POINT",
                        "dataset:granularity": "HOURLY",
                        "dataset:dataType": "FORECAST"
                    }
                }
            ],
