                        "@context": "https://raw.githubusercontent.com/beckn/schemas/main/schema/PriceSpecification/v2.1/context.jsonld",
                        "@type": "PriceSpecification",
                        "currency": "INR",
                        "value": 4999.00,
                        "components": [
                            {
                                "type": "UNIT",
                                "value": 4236.44,
                                "currency": "INR",
                                "description": "Rainwater Probability Maharashtra March 2025 - Parquet export"
                            },
                            {
                                "type": "TAX",
                                "value": 762.56,
                                "currency": "INR",
                                "description": "GST 18%"
                            }
                        ]
                    }
                }
            ],
            "participants": [
                {
                    "id": "climate-data-provider-001",
                    "descriptor": {
                        "name": "Climate Data Provider",
                        "shortDesc": "Provider of climate and meteorological data"
                    },
                    "participantAttributes": {
                        "@context": "https://raw.githubusercontent.com/beckn/schemas/main/schema/Provider/v2.1/context.jsonld",
                        "@type": "Provider",
                        "id": "climate-data-provider-001",
                        "descriptor": {
                            "name": "Climate Data Provider"
                        }
                    }
                },
                {
                    "id": "buyer-hydrology-lab-001",
                    "descriptor": {
                        "name": "Hydrology Lab, Delhi"
                    },
                    "participantAttributes": {
                        "@context": "https://raw.githubusercontent.com/beckn/schemas/main/schema/Consumer/v2.0/context.jsonld",
                        "@type": "Consumer",
                        "role": "buyer",
                        "organization": {
                            "id": "buyer-hydrology-lab-001",
                            "name": "Hydrology Lab, Delhi"
                        }
                    }
                }
            ],
